args.script:
using UnityEngine;
using UnityEditor;

string[] prefabPaths = {
    "Assets/TJGenerators/DownloadedAssets/3d_kenney_castle_kit_ground_hills/kenney_castle_kit_ground_hills.prefab",
    "Assets/TJGenerators/DownloadedAssets/3d_kaykit_medieval_hexagon_pack_mountain_a_grass_trees/kaykit_medieval_hexagon_pack_mountain_a_grass_trees.prefab",
    "Assets/TJGenerators/DownloadedAssets/3d_kaykit_medieval_hexagon_pack_hills_b_trees/kaykit_medieval_hexagon_pack_hills_b_trees.prefab",
    "Assets/TJGenerators/DownloadedAssets/3d_kenney_holiday_kit_snow_bunker/kenney_holiday_kit_snow_bunker.prefab"
};

string[] names = {
    "Terrain_GroundHills",
    "Terrain_MountainGrassTrees",
    "Terrain_HillsBTrees",
    "Terrain_SnowBunker"
};

Vector3[] positions = {
    new Vector3(-4, 0, 0),
    new Vector3(-1.3f, 0, 0),
    new Vector3(1.3f, 0, 0),
    new Vector3(4, 0, 0)
};

Vector3[] scales = {
    new Vector3(10, 10, 10),
    new Vector3(100, 100, 100),
    new Vector3(100, 100, 100),
    new Vector3(3, 3, 3)
};

for (int i = 0; i < prefabPaths.Length; i++)
{
    var prefab = AssetDatabase.LoadAssetAtPath<GameObject>(prefabPaths[i]);
    if (prefab == null)
    {
        Debug.LogError($"Failed to load prefab: {prefabPaths[i]}");
        continue;
    }
    var go = (GameObject)PrefabUtility.InstantiatePrefab(prefab);
    go.name = names[i];
    go.transform.position = positions[i];
    go.transform.localScale = scales[i];
    Debug.Log($"Instantiated {names[i]} at {positions[i]} with scale {scales[i]}");
}

