{
    var go = GameObject.Find(name);
    if (go == null) { Debug.Log($"{name}: NOT FOUND"); continue; }

    var renderers = go.GetComponentsInChildren<MeshRenderer>();
    Debug.Log($"=== {name} ({renderers.Length} renderers) ===");
    foreach (var r in renderers)
    {
        for (int i = 0; i < r.sharedMaterials.Length; i++)
        {
            var mat = r.sharedMaterials[i];
            if (mat == null)
                Debug.Log($"  Material[{i}]: NULL (missing/pink)");
            else
                Debug.Log($"  Material[{i}]: '{mat.name}' shader='{mat.shader.name}'");
        }
    }
}

