using UnityEngine;
using UnityEditor;

// Read the .mat files to find what shader they originally referenced
string[] matPaths = {
    "Assets/Pure Poly/Free Low Poly Nature Pack/Materials/PP_Ground.mat",
    "Assets/Pure Poly/Free Low Poly Nature Pack/Materials/PP_Standard_Material.mat",
    "Assets/Pure Poly/Free Low Poly Nature Pack/Materials/PP_Water.mat"
};

foreach (var p in matPaths)
{
    var content = System.IO.File.ReadAllText(p);
    // Find the shader reference
    var shaderMatch = System.Text.RegularExpressions.Regex.Match(content, @"m_Shader:\s*\{[^}]*m_FileID:\s*(\d+)[^}]*m_GUID:\s*([a-f0-9]+)");
    if (shaderMatch.Success)
        Debug.Log($"{System.IO.Path.GetFileName(p)} => shader FileID={shaderMatch.Groups[1].Value} GUID={shaderMatch.Groups[2].Value}");

    // Also look for the shader name string
    var nameMatch = System.Text.RegularExpressions.Regex.Match(content, @"name:\s*(.+)");
    if (nameMatch.Success)
        Debug.Log($"  name field: {nameMatch.Groups[1].Value}");
}

