        {
            Debug.LogWarning($"NULL material on '{r.gameObject.name}'");
            issueCount++;
            continue;
        }

        bool hasIssue = false;
        string issue = "";

        // Check for error shader
        if (mat.shader.name == "Hidden/InternalErrorShader")
        {
            issue += $"[ErrorShader] ";
            hasIssue = true;
        }

        // Check for URP shader on built-in pipeline
        if (mat.shader.name.Contains("Universal Render Pipeline") || mat.shader.name.Contains("URP"))
        {
            issue += $"[URP shader on Built-in] ";
            hasIssue = true;
        }

        // Check for missing main texture on Standard shader
        if (mat.shader.name == "Standard" && mat.mainTexture == null)
        {
            // Check if _BaseMap or _MainTex is expected but missing
            var mainTex = mat.GetTexture("_MainTex");
            var baseMap = mat.GetTexture("_BaseMap");
            if (mainTex == null && baseMap == null)
            {
                issue += $"[No texture] ";
                hasIssue = true;
            }
        }

        if (hasIssue)
        {
            Debug.LogWarning($"Material issue on '{r.gameObject.name}': mat='{mat.name}' shader='{mat.shader.name}' {issue}");
            issueCount++;
        }
    }
}
Debug.Log($"Total material issues in scene: {issueCount}");

