// List all texture properties
var shader = mat.shader;
for (int i = 0; i < ShaderUtil.GetPropertyCount(shader); i++)
{
    var propName = ShaderUtil.GetPropertyName(shader, i);
    var propType = ShaderUtil.GetPropertyType(shader, i);
    if (propType == ShaderUtil.ShaderPropertyType.TexEnv)
    {
        var tex = mat.GetTexture(propName);
        Debug.Log($"  Texture '{propName}': {(tex != null ? tex.name : "null")}");
    }
}

// Check color properties
Debug.Log($"  _Color: {mat.GetColor("_Color")}");
Debug.Log($"  _BaseColor: {mat.color}");

// Read the .mat file for original URP properties
var lines = System.IO.File.ReadAllLines("Assets/Pure Poly/Free Low Poly Nature Pack/Materials/PP_Water.mat");
foreach (var line in lines)
{
    if (line.Contains("_BaseColor") || line.Contains("_Color") || line.Contains("m_Color") || line.Contains("_Surface"))
        Debug.Log($"  .mat: {line.Trim()}");
}

using UnityEngine;
using UnityEditor;

// Fix PP_Water - set up as a proper transparent water material on Standard shader
var mat = AssetDatabase.LoadAssetAtPath<Material>("Assets/Pure Poly/Free Low Poly Nature Pack/Materials/PP_Water.mat");

// Standard shader transparent setup
mat.SetFloat("_Mode", 3); // Transparent mode
mat.SetOverrideTag("RenderType", "Transparent");
mat.SetInt("_SrcBlend", (int)UnityEngine.Rendering.BlendMode.SrcAlpha);
mat.SetInt("_DstBlend", (int)UnityEngine.Rendering.BlendMode.OneMinusSrcAlpha);
mat.SetInt("_ZWrite", 0);
mat.DisableKeyword("_ALPHATEST_ON");
mat.EnableKeyword("_ALPHABLEND_ON");
mat.DisableKeyword("_ALPHAPREMULTIPLY_ON");
mat.renderQueue = 3000;

// Water color is already set: light blue with alpha 0.42
// Set metallic and smoothness for water look
mat.SetFloat("_Metallic", 0f);
mat.SetFloat("_Glossiness", 0.9f);

EditorUtility.SetDirty(mat);
AssetDatabase.SaveAssets();
Debug.Log($"Fixed PP_Water: Transparent water material, color={mat.color}, renderQueue={mat.renderQueue}");

