Undo.RecordObject(terrain, "Set Terrain Material Type");
var propInfo = terrain.GetType().GetProperty("materialType");
if (propInfo != null)
    Debug.Log($"materialType property found, can write: {propInfo.CanWrite}");
else
    Debug.Log($"materialType property NOT found via reflection");

// Direct assignment attempt
terrain.materialType = Terrain.MaterialType.BuiltInStandard;
