// Check if the scene Terrain file has the Custom override
var scenePath = "Assets/Pure Poly/Free Low Poly Nature Pack/Scenes/Demo_Terrain.unity";
var sceneContent = System.IO.File.ReadAllText(scenePath);
var match = System.Text.RegularExpressions.Regex.Match(sceneContent, @"m_MaterialType:\s*(\d+)");
if (match.Success)
    Debug.Log($"Scene file m_MaterialType = {match.Groups[1].Value}");

