using UnityEngine;
using UnityEditor;

var scenePath = "Assets/Pure Poly/Free Low Poly Nature Pack/Scenes/Demo_Terrain.unity";
var content = System.IO.File.ReadAllText(scenePath);

// Search for MaterialType in different forms
var patterns = new[] { "m_MaterialType", "MaterialType", "materialType" };
foreach (var p in patterns)
{
    var idx = content.IndexOf(p);
    if (idx >= 0)
    {
        var start = Mathf.Max(0, idx - 50);
        var end = Mathf.Min(content.Length, idx + 100);
        Debug.Log($"Found '{p}' at {idx}: {content.Substring(start, end - start)}");
    }
    else
    {
        Debug.Log($"'{p}' NOT found in scene file");
    }
}

// The materialType might be stored differently in the serialized data
// Let's look at the Terrain component section more carefully
var terrainIdx = content.IndexOf("Terrain:");
if (terrainIdx >= 0)
{
    var end = Mathf.Min(content.Length, terrainIdx + 3000);
    var section = content.Substring(terrainIdx, end - terrainIdx);
    // Find any "Custom" or "3" that could be the material type
    var lines = section.Split('\n');
    for (int i = 0; i < lines.Length; i++)
    {
        if (lines[i].Contains("Material") || lines[i].Contains("3") && lines[i].Trim().Length < 5)
            Debug.Log($"  L{i}: {lines[i].TrimEnd()}");
    }
}

