using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 鼠标点地移动角色控制器：左键点击地面移动、右键拖拽旋转视角、滚轮缩放。
    /// </summary>
    [RequireComponent(typeof(CharacterController))]
    public class ClickToMoveController : MonoBehaviour
    {
        [Header("移动")]
        [SerializeField] private float _moveSpeed = 6f;
        [SerializeField] private float _rotationSpeed = 10f;
        [SerializeField] private float _stopDistance = 0.2f;

        [Header("摄像机")]
        [SerializeField] private float _orbitSpeed = 150f;
        [SerializeField] private float _zoomSpeed = 5f;
        [SerializeField] private float _minZoomDist = 4f;
        [SerializeField] private float _maxZoomDist = 20f;

        private CharacterController _cc;
        private Camera _cam;
        private Vector3 _targetPos;
        private bool _hasTarget;
        private float _currentYaw;
        private float _camDistance;
        private bool _isRightDragging;
        private int _groundLayerMask;

        private void Awake()
        {
            _cc = GetComponent<CharacterController>();
            _cam = GetComponentInChildren<Camera>();
            _targetPos = transform.position;
            _currentYaw = transform.eulerAngles.y;
            _groundLayerMask = LayerMask.GetMask("Default");

            CalcCameraDistance();
        }

        private void Update()
        {
            HandleClickMove();
            HandleOrbit();
            HandleZoom();
            MoveCharacter();
            UpdateCamera();
        }

        #region 移动

        private void HandleClickMove()
        {
            if (Input.GetMouseButtonDown(0) && !_isRightDragging)
            {
                Ray ray = _cam.ScreenPointToRay(Input.mousePosition);
                if (Physics.Raycast(ray, out RaycastHit hit, 200f, _groundLayerMask))
                {
                    _targetPos = hit.point;
                    _hasTarget = true;
                }
            }
        }

        private void MoveCharacter()
        {
            Vector3 dir = _targetPos - transform.position;
            dir.y = 0f;

            if (dir.magnitude < _stopDistance)
            {
                _hasTarget = false;
                _cc.Move(new Vector3(0, -9.8f, 0) * Time.deltaTime);
                return;
            }

            // 旋转朝向目标
            Quaternion targetRot = Quaternion.LookRotation(dir.normalized);
            transform.rotation = Quaternion.Slerp(transform.rotation, targetRot, _rotationSpeed * Time.deltaTime);

            // 移动
            Vector3 motion = dir.normalized * (_moveSpeed * Time.deltaTime);
            motion.y = -9.8f * Time.deltaTime;
            _cc.Move(motion);
        }

        #endregion

        #region 摄像机

        private void HandleOrbit()
        {
            if (Input.GetMouseButtonDown(1))
                _isRightDragging = true;
            if (Input.GetMouseButtonUp(1))
                _isRightDragging = false;

            if (!_isRightDragging) return;

            float mouseX = Input.GetAxis("Mouse X");
            _currentYaw += mouseX * _orbitSpeed * Time.deltaTime;
        }

        private void HandleZoom()
        {
            float scroll = Input.GetAxis("Mouse ScrollWheel");
            if (Mathf.Abs(scroll) > 0.01f)
            {
                _camDistance -= scroll * _zoomSpeed;
                _camDistance = Mathf.Clamp(_camDistance, _minZoomDist, _maxZoomDist);
            }
        }

        private void CalcCameraDistance()
        {
            if (_cam == null) return;
            Vector3 localOffset = _cam.transform.localPosition;
            localOffset.y = Mathf.Max(localOffset.y, 0.1f);
            float pitchRad = Mathf.Deg2Rad * Mathf.Abs(_cam.transform.localEulerAngles.x);
            _camDistance = localOffset.y / Mathf.Max(Mathf.Sin(pitchRad), 0.1f);
            _camDistance = Mathf.Clamp(_camDistance, _minZoomDist, _maxZoomDist);
        }

        private void UpdateCamera()
        {
            if (_cam == null) return;

            float pitch = _cam.transform.localEulerAngles.x;
            if (pitch > 180f) pitch -= 360f;
            float pitchRad = pitch * Mathf.Deg2Rad;

            float height = _camDistance * Mathf.Sin(pitchRad);
            float back = _camDistance * Mathf.Cos(pitchRad);

            Quaternion yawRot = Quaternion.Euler(0, _currentYaw, 0);
            Vector3 offset = yawRot * new Vector3(0, height, -back);

