using UnityEngine;
using UnityEditor;

// Find all animation clips related to Knight
var guids = AssetDatabase.FindAssets("t:AnimationClip", new[] { "Assets/Quaternius/KayKit_Adventurers_2.0" });
Debug.Log($"Total animation clips: {guids.Length}");

foreach (var g in guids)
{
    var path = AssetDatabase.GUIDToAssetPath(g);
    var clip = AssetDatabase.LoadAssetAtPath<AnimationClip>(path);
    if (clip != null)
        Debug.Log($"  {clip.name} ({clip.length:F2}s) @ {path}");
}

// Also check the Knight prefab for animator
var knight = GameObject.Find("Knight");
if (knight != null)
{
    var anim = knight.GetComponentInChildren<Animator>();
    Debug.Log($"Animator: {(anim != null ? anim.gameObject.name : "none")}");

    // Check children for rig
    foreach (Transform child in knight.transform)
    {
        Debug.Log($"  Child: {child.name}");
    }
}

using UnityEngine;
using UnityEditor;

// Search broader for KayKit Adventurers animations
var guids = AssetDatabase.FindAssets("t:AnimationClip", new[] { "Assets/Quaternius" });
Debug.Log($"All Quaternius animation clips: {guids.Length}");

// Also search in DownloadedAssets
var guids2 = AssetDatabase.FindAssets("t:AnimationClip", new[] { "Assets/TJGenerators/DownloadedAssets" });
Debug.Log($"DownloadedAssets animation clips: {guids2.Length}");

// Check the Rig_Medium child for Animator component
var knight = GameObject.Find("Knight");
var rig = knight.transform.Find("Rig_Medium");
if (rig != null)
{
    Debug.Log($"Rig_Medium found, components:");
    foreach (var c in rig.GetComponents<Component>())
        Debug.Log($"  {c.GetType().Name}");
}

// Check SkinnedMeshRenderer on body parts
foreach (Transform child in knight.transform)
{
    var smr = child.GetComponent<SkinnedMeshRenderer>();
    var mr = child.GetComponent<MeshRenderer>();
    if (smr != null) Debug.Log($"  {child.name}: SkinnedMeshRenderer (bones={smr.bones.Length})");
    if (mr != null) Debug.Log($"  {child.name}: MeshRenderer");
}

