using UnityEngine;
using UnityEditor;

// Check all FBX files in KayKit Adventurers for more animations
var fbxGuids = AssetDatabase.FindAssets("t:Model", new[] { "Assets/Quaternius/KayKit_Adventurers_2.0" });
Debug.Log($"FBX models: {fbxGuids.Length}");

foreach (var g in fbxGuids)
{
    var path = AssetDatabase.GUIDToAssetPath(g);
    // Check import settings for animation type
    var importer = AssetImporter.GetAtPath(path) as ModelImporter;
    if (importer != null)
    {
        Debug.Log($"  {System.IO.Path.GetFileName(path)}: animType={importer.animationType} rigType={importer.animationType}");

        // List clips in this FBX
        var clips = AssetDatabase.LoadAllAssetsAtPath(path);
        foreach (var c in clips)
        {
            if (c is AnimationClip ac && !ac.name.StartsWith("__"))
                Debug.Log($"    Clip: {ac.name} ({ac.length:F2}s)");
        }
    }
}

using UnityEngine;
using UnityEditor;
using UnityEditor.Animations;

// Create AnimatorController for Knight
var savePath = "Assets/_Modules/HomeBase/Animations/KnightController.controller";
var folder = System.IO.Path.GetDirectoryName(savePath);
if (!AssetDatabase.IsValidFolder(folder))
    AssetDatabase.CreateFolder("Assets/_Modules/HomeBase", "Animations");

var controller = AnimatorController.CreateAnimatorControllerAtPath(savePath);
controller.AddParameter("Speed", AnimatorControllerParameterType.Float);
controller.AddParameter("IsGrounded", AnimatorControllerParameterType.Bool);
controller.AddParameter("Hit", AnimatorControllerParameterType.Trigger);
controller.AddParameter("Die", AnimatorControllerParameterType.Trigger);
controller.AddParameter("Interact", AnimatorControllerParameterType.Trigger);

// Load animation clips
string generalPath = "Assets/Quaternius/KayKit_Adventurers_2.0/Animations/fbx/Rig_Medium/Rig_Medium_General.fbx";
string movePath = "Assets/Quaternius/KayKit_Adventurers_2.0/Animations/fbx/Rig_Medium/Rig_Medium_MovementBasic.fbx";

var allClips = new System.Collections.Generic.Dictionary<string, AnimationClip>();
foreach (var clip in AssetDatabase.LoadAllAssetsAtPath(generalPath))
    if (clip is AnimationClip ac && !ac.name.StartsWith("__") && !ac.name.Contains("Pose"))
        allClips[ac.name] = ac;
foreach (var clip in AssetDatabase.LoadAllAssetsAtPath(movePath))
    if (clip is AnimationClip ac && !ac.name.StartsWith("__") && !ac.name.Contains("Pose"))
        allClips[ac.name] = ac;

Debug.Log($"Loaded {allClips.Count} clips");

// Helper to add state
var rootSM = controller.layers[0].stateMachine;

var idleA = rootSM.AddState("Idle_A", new Vector3(0, 0, 0));
var idleB = rootSM.AddState("Idle_B", new Vector3(200, 0, 0));
var walkA = rootSM.AddState("Walking_A", new Vector3(400, 0, 0));
var walkB = rootSM.AddState("Walking_B", new Vector3(600, 0, 0));
var walkC = rootSM.AddState("Walking_C", new Vector3(800, 0, 0));
var runA = rootSM.AddState("Running_A", new Vector3(1000, 0, 0));
var runB = rootSM.AddState("Running_B", new Vector3(1200, 0, 0));
var hitA = rootSM.AddState("Hit_A", new Vector3(400, 200, 0));
var hitB = rootSM.AddState("Hit_B", new Vector3(600, 200, 0));
var deathA = rootSM.AddState("Death_A", new Vector3(0, 200, 0));
var deathB = rootSM.AddState("Death_B", new Vector3(200, 200, 0));
var interactState = rootSM.AddState("Interact", new Vector3(800, 200, 0));
var jumpStart = rootSM.AddState("Jump_Start", new Vector3(0, 400, 0));
var jumpIdle = rootSM.AddState("Jump_Idle", new Vector3(200, 400, 0));
var jumpLand = rootSM.AddState("Jump_Land", new Vector3(400, 400, 0));

// Assign clips
if (allClips.ContainsKey("Idle_A")) idleA.motion = allClips["Idle_A"];
if (allClips.ContainsKey("Idle_B")) idleB.motion = allClips["Idle_B"];
if (allClips.ContainsKey("Walking_A")) walkA.motion = allClips["Walking_A"];
if (allClips.ContainsKey("Walking_B")) walkB.motion = allClips["Walking_B"];
if (allClips.ContainsKey("Walking_C")) walkC.motion = allClips["Walking_C"];
if (allClips.ContainsKey("Running_A")) runA.motion = allClips["Running_A"];
if (allClips.ContainsKey("Running_B")) runB.motion = allClips["Running_B"];
if (allClips.ContainsKey("Hit_A")) hitA.motion = allClips["Hit_A"];
if (allClips.ContainsKey("Hit_B")) hitB.motion = allClips["Hit_B"];
if (allClips.ContainsKey("Death_A")) deathA.motion = allClips["Death_A"];
if (allClips.ContainsKey("Death_B")) deathB.motion = allClips["Death_B"];
if (allClips.ContainsKey("Interact")) interactState.motion = allClips["Interact"];
if (allClips.ContainsKey("Jump_Start")) jumpStart.motion = allClips["Jump_Start"];
if (allClips.ContainsKey("Jump_Idle")) jumpIdle.motion = allClips["Jump_Idle"];
if (allClips.ContainsKey("Jump_Land")) jumpLand.motion = allClips["Jump_Land"];

// Set default state
rootSM.defaultState = idleA;

// -- Transitions --
// Idle <-> Walk (Speed > 0.1)
var t = idleA.AddTransition(walkA);
t.hasExitTime = false; t.duration = 0.25f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.Greater, parameter = "Speed", threshold = 0.1f } };

t = idleB.AddTransition(walkA);
t.hasExitTime = false; t.duration = 0.25f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.Greater, parameter = "Speed", threshold = 0.1f } };

t = walkA.AddTransition(idleA);
t.hasExitTime = false; t.duration = 0.2f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.Less, parameter = "Speed", threshold = 0.1f } };

// Walk <-> Run (Speed > 3)
t = walkA.AddTransition(runA);
t.hasExitTime = false; t.duration = 0.2f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.Greater, parameter = "Speed", threshold = 3f } };

t = runA.AddTransition(walkA);
t.hasExitTime = false; t.duration = 0.25f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.Less, parameter = "Speed", threshold = 3f } };

// Idle variants loop
t = idleA.AddTransition(idleB);
t.hasExitTime = true; t.duration = 0.3f; t.exitTime = 0.9f;

t = idleB.AddTransition(idleA);
t.hasExitTime = true; t.duration = 0.3f; t.exitTime = 0.9f;

// Walk variants
t = walkA.AddTransition(walkB);
t.hasExitTime = true; t.duration = 0.15f; t.exitTime = 0.85f;

t = walkB.AddTransition(walkC);
t.hasExitTime = true; t.duration = 0.15f; t.exitTime = 0.85f;

t = walkC.AddTransition(walkA);
t.hasExitTime = true; t.duration = 0.15f; t.exitTime = 0.85f;

// Run variants
t = runA.AddTransition(runB);
t.hasExitTime = true; t.duration = 0.15f; t.exitTime = 0.85f;

t = runB.AddTransition(runA);
t.hasExitTime = true; t.duration = 0.15f; t.exitTime = 0.85f;

// Hit -> Idle
t = hitA.AddTransition(idleA);
t.hasExitTime = true; t.duration = 0.2f; t.exitTime = 0.8f;

t = hitB.AddTransition(idleA);
t.hasExitTime = true; t.duration = 0.2f; t.exitTime = 0.8f;

// Any -> Hit
t = rootSM.AddAnyStateTransition(hitA);
t.hasExitTime = false; t.duration = 0.1f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.If, parameter = "Hit", threshold = 0 } };

// Any -> Death
t = rootSM.AddAnyStateTransition(deathA);
t.hasExitTime = false; t.duration = 0.1f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.If, parameter = "Die", threshold = 0 } };

// Any -> Interact
t = rootSM.AddAnyStateTransition(interactState);
t.hasExitTime = false; t.duration = 0.15f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.If, parameter = "Interact", threshold = 0 } };

// Interact -> Idle
t = interactState.AddTransition(idleA);
t.hasExitTime = true; t.duration = 0.2f; t.exitTime = 0.85f;

// Jump (when not grounded)
t = rootSM.AddAnyStateTransition(jumpStart);
t.hasExitTime = false; t.duration = 0.1f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.IfNot, parameter = "IsGrounded", threshold = 0 } };

t = jumpStart.AddTransition(jumpIdle);
t.hasExitTime = true; t.duration = 0.1f; t.exitTime = 0.85f;

t = jumpIdle.AddTransition(jumpLand);
t.hasExitTime = false; t.duration = 0.1f; t.conditions = new[] { new AnimatorCondition { mode = AnimatorConditionMode.If, parameter = "IsGrounded", threshold = 0 } };

t = jumpLand.AddTransition(idleA);
t.hasExitTime = true; t.duration = 0.15f; t.exitTime = 0.85f;

AssetDatabase.SaveAssets();
Debug.Log($"AnimatorController created at {savePath} with {controller.layers[0].stateMachine.states.Length} states");

